module D_latch (
    input wire data_in,
    input wire en,
    output reg q,
    output reg q_n
);
    always @(data_in or en) begin
        if (en) begin
            q <= data_in;
        end
        // When enable is low, q retains its value
    end

    always @(q) begin
        q_n <= ~q;
    end
endmodule
